script.text:
      /* <flatten type="Javascript"> */
function load$EmployeeSalaryInformationGrid$(g) {
  g.add_onResponseComplete(on$EmployeeSalaryInformationGrid$ResponseComplete);
  g.add_commandEvent(on$EmployeeSalaryInformationGrid$ExecuteCommand);
}
function dispose$EmployeeSalaryInformationGrid$(g) {
  try {g.remove_commandEvent(on$EmployeeSalaryInformationGrid$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$EmployeeSalaryInformationGrid$ResponseComplete);} catch (ex) {}
}
function on$EmployeeSalaryInformationGrid$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender;
  switch (action) {
    case 'ImportData':
      if (e.type.Value == '110') show$Form(g, 'hrEmployeeSalaryInformationImport');
        else show$Form(g, 'hrEmployeeSalaryInformationAllowanceImport');
      break;
    case 'Download':
      if (e.type.Value == '210') request$Download(g, action, g._key);
        else request$Download(g, 'Allowance', g._$key);
      break;
    default:
      break;
  }
}
function on$EmployeeSalaryInformationGrid$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Download':
      g._key = result[0].Value;
      break;
    case 'Allowance':
      g._$key = result[0].Value;
    default:
      break;
  }
}
function show$Form(g, c) {(!g._denyEdit) ? (g._authorize == 1) ? g.showForm(c) : $message.show($df.getResources(g._language, "Message.NotAccess")) : $message.show(g._denyMessage);}
/* </flatten> */
function request$Download(g, a, b) {
  g.request(g, a, a, []);
  var r = $get('requestFormData');
  if (!r) r = $func.requestFormData();
  var query = '?a=1&t=&TransferID;' + '&k=' + b + String.format('&r={0}', Math.random());
  r.action = $func.resolveClientUrl('~/AppHandler/Transfer.ashx' + query, g._baseUrl);
  if (!$func.isIE) r.target = '_blank';
  r.submit();
  if (g._activeCell) g._activeCell.focus();
}
